// GROWTH-3: delta 페어링 포함 검증
// score: 1(나쁨) | 2(보통) | 3(좋음)
// rationale: 근거 (필수, 빈 값 거부)
// decision_ref: 평가 대상 결정 ID
// actor: 평가 대상 RA 에이전트 ID
// agent_judgment: 원래 RA 결과 JSON (선택 — 있으면 delta 계산)
// human_correction: 인간이 정정한 내용 (선택)
//   { match, transition_proposed, comment } — 수정된 항목만 포함
// dimensions: 차원별 평가 (선택)
//   { match_correct: bool, reasoning_quality: 1-3, citation_valid: bool }
const raw = $json;
const input = raw.body || raw;

const score = parseInt(input.score);
if (![1, 2, 3].includes(score)) {
  throw new Error('score must be 1, 2, or 3. Got: ' + JSON.stringify(input.score));
}

const validActors = ['ra_us', 'ra_eu', 'ra_kr', 'op_manager', 'n8n_manager', 'infra_t3610', 'infra_gx10', 'infra_rpi'];
if (!validActors.includes(input.actor)) {
  throw new Error('Unknown actor: ' + input.actor);
}

// rationale 필수화: 빈 값은 'ungrounded' 태그 부여
const rationale = (input.rationale || '').trim().slice(0, 500);
const rationaleTagged = rationale.length === 0 ? '[ungrounded]' : rationale;

// dimensions 검증
let dimensions = null;
if (input.dimensions) {
  const d = input.dimensions;
  const rq = parseInt(d.reasoning_quality);
  if (d.match_correct !== undefined && typeof d.match_correct !== 'boolean') {
    throw new Error('dimensions.match_correct must be boolean');
  }
  if (d.reasoning_quality !== undefined && ![1, 2, 3].includes(rq)) {
    throw new Error('dimensions.reasoning_quality must be 1, 2, or 3');
  }
  dimensions = {
    match_correct: typeof d.match_correct === 'boolean' ? d.match_correct : null,
    reasoning_quality: d.reasoning_quality !== undefined ? rq : null,
    citation_valid: typeof d.citation_valid === 'boolean' ? d.citation_valid : null
  };
}

// delta 계산: agent_judgment와 human_correction 비교
let delta = null;
const aj = input.agent_judgment || null;
const hc = input.human_correction || null;
if (aj && hc) {
  const changed = {};
  if (hc.match !== undefined && hc.match !== aj.match) {
    changed.match = { agent: aj.match, human: hc.match };
  }
  if (hc.transition_proposed !== undefined && hc.transition_proposed !== aj.transition_proposed) {
    changed.transition = { agent: aj.transition_proposed, human: hc.transition_proposed };
  }
  if (hc.comment !== undefined) {
    changed.comment = { agent: (aj.comment || '').slice(0, 100), human: hc.comment.slice(0, 100) };
  }
  if (Object.keys(changed).length > 0) {
    delta = { changed, self_correction: true };
  } else {
    delta = { changed: {}, self_correction: false };
  }
}

return [{
  json: {
    score,
    rationale: rationaleTagged,
    rationale_ungrounded: rationale.length === 0,
    decision_ref: input.decision_ref || null,
    actor: input.actor,
    agent_judgment: aj,
    human_correction: hc,
    delta,
    dimensions,
    evaluated_by: 'human',
    evaluated_at: new Date().toISOString()
  }
}];

// 가중치 반영 연결 자리 [IF]
// 평가된 사안 영역별 가중치 조정 연결점
// 조정 공식은 비워둠 — 학습이 정함
// WEIGHT_ADJUSTMENT_CONFIG_JSON 또는 payload.weight_config_json에서 읽음
const env = (typeof process !== 'undefined' && process.env) ? process.env : {};
const feedback = $node['평가 입력 검증'].json;

let config = {};
let configStatus = 'empty';
const configRaw = env.WEIGHT_ADJUSTMENT_CONFIG_JSON || feedback.weight_config_json || null;
if (configRaw) {
  try {
    config = typeof configRaw === 'string' ? JSON.parse(configRaw) : configRaw;
    configStatus = 'loaded';
  } catch (e) {
    config = {};
    configStatus = 'parse_error:' + e.message;
  }
}

const configMeta = {
  source: configRaw ? 'env_or_payload' : 'empty_default',
  status: configStatus,
  has_formula: Boolean(config.adjustment_formula)
};

// 조정 공식이 비어 있으면 기록만 하고 패스
if (!config.adjustment_formula) {
  return [{
    json: {
      _weight_adjustment: 'skipped_formula_empty',
      _weight_adjustment_config: configMeta,
      feedback_recorded: true,
      score: feedback.score,
      actor: feedback.actor,
      has_delta: feedback.delta !== null,
      self_correction: feedback.delta ? feedback.delta.self_correction : false
    }
  }];
}

// 공식이 채워지면 여기서 가중치 조정 로직 실행 (운영·학습이 채움)
// 현재는 interface만 존재 — 내부 구현 없음
return [{
  json: {
    _weight_adjustment: 'formula_not_implemented',
    _weight_adjustment_config: configMeta,
    feedback_recorded: true,
    score: feedback.score,
    actor: feedback.actor
  }
}];
